#include "common.h"

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

void lud_diagonal(float *m, int matrix_dim, int offset) {
    float shadow[BLOCK_SIZE * BLOCK_SIZE];
    int i, j, tx;
    int array_offset = offset * matrix_dim + offset;

    // Parallelize the copy to local shadow with explicit thread mapping
    #pragma omp parallel for
    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        int local_array_offset = array_offset;
        for (i = 0; i < BLOCK_SIZE; i++) {
            shadow[i * BLOCK_SIZE + tx] = m[local_array_offset + tx];
            local_array_offset += matrix_dim;
        }
    }

    // Sequential execution for the diagonal block LU decomposition as per original kernel logic
    // The original kernel uses barriers to synchronize, implying a sequential wavefront within the block
    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        // Step 1: Update column i for rows > i
        for (tx = i + 1; tx < BLOCK_SIZE; tx++) {
            float sum = 0.0f;
            for (j = 0; j < i; j++) {
                sum += shadow[tx * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + i];
            }
            shadow[tx * BLOCK_SIZE + i] -= sum;
            shadow[tx * BLOCK_SIZE + i] /= shadow[i * BLOCK_SIZE + i];
        }

        // Step 2: Update row i+1 for columns > i (which is all columns in this context since tx iterates full width)
        // Original code: if (tx>i) ... shadow[(i+1)*BLOCK_SIZE+tx] ...
        // This updates the row i+1 using the newly computed column i values
        for (tx = i + 1; tx < BLOCK_SIZE; tx++) {
            float sum = 0.0f;
            for (j = 0; j < i + 1; j++) {
                sum += shadow[(i + 1) * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + tx];
            }
            shadow[(i + 1) * BLOCK_SIZE + tx] -= sum;
        }
    }

    // Copy back from shadow to global memory
    array_offset = (offset + 1) * matrix_dim + offset;
    #pragma omp parallel for
    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        int local_array_offset = array_offset;
        for (i = 1; i < BLOCK_SIZE; i++) {
            m[local_array_offset + tx] = shadow[i * BLOCK_SIZE + tx];
            local_array_offset += matrix_dim;
        }
    }
}

void lud_perimeter(float *m, int matrix_dim, int offset) {
    float dia[BLOCK_SIZE * BLOCK_SIZE];
    float peri_row[BLOCK_SIZE * BLOCK_SIZE];
    float peri_col[BLOCK_SIZE * BLOCK_SIZE];
    int i, j, array_offset, idx;
    int bx = 0; // In the original CL code, bx is group_id. In the loop context of the host, this function processes one block column/row pair.
                // However, looking at the original host code, it launches perimeter with multiple groups (bx).
                // To translate this correctly to OpenMP without changing the algorithm structure significantly,
                // we must replicate the logic that was distributed across groups.
                // The original host loop:
                // global_work2[0] = BLOCK_SIZE * 2 * ((matrix_dim-i)/BLOCK_SIZE-1)
                // This implies multiple blocks are processed in parallel.
                // But the provided kernel `lud_perimeter` takes `offset` and uses `bx` (group_id) to determine which block it works on.
                // Since we are translating the kernel logic to a function called in a loop or parallel region,
                // we need to handle the `bx` dimension.
                // Actually, looking at the host code in Source File 3:
                // It calls `lud_perimeter` kernel with global_work2 covering multiple blocks.
                // The kernel uses `bx = get_group_id(0)` to select the specific block column.
                // To translate this to OpenMP, we should parallelize over the blocks (bx).

    // We will parallelize over the blocks (bx) that need to be processed for this offset.
    int num_blocks = (matrix_dim - offset) / BLOCK_SIZE - 1;

    #pragma omp parallel for private(i, j, array_offset, idx, dia, peri_row, peri_col)
    for (int bx = 0; bx < num_blocks; bx++) {
        // Reset local arrays for each block
        for(int k=0; k<BLOCK_SIZE*BLOCK_SIZE; k++) { dia[k]=0.0; peri_row[k]=0.0; peri_col[k]=0.0; }

        int tx_limit = BLOCK_SIZE * 2; // Total threads simulated per block group in original

        // Simulate the two parts of the original kernel: tx < BLOCK_SIZE and tx >= BLOCK_SIZE
        // Part 1: tx < BLOCK_SIZE (Loads dia upper/lower? and peri_row)
        // Original: idx = tx. Loads dia[0..BLOCK_SIZE/2-1] and peri_row[0..BLOCK_SIZE-1]
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            idx = tx;
            array_offset = offset * matrix_dim + offset;
            for (i = 0; i < BLOCK_SIZE / 2; i++) {
                dia[i * BLOCK_SIZE + idx] = m[array_offset + idx];
                array_offset += matrix_dim;
            }

            array_offset = offset * matrix_dim + (offset + (bx + 1) * BLOCK_SIZE);
            for (i = 0; i < BLOCK_SIZE; i++) {
                peri_row[i * BLOCK_SIZE + idx] = m[array_offset + idx];
                array_offset += matrix_dim;
            }
        }

        // Part 2: tx >= BLOCK_SIZE (Loads dia rest and peri_col)
        // Original: idx = tx - BLOCK_SIZE. Loads dia[BLOCK_SIZE/2..BLOCK_SIZE-1] and peri_col[0..BLOCK_SIZE-1]
        for (int tx = BLOCK_SIZE; tx < 2 * BLOCK_SIZE; tx++) {
            idx = tx - BLOCK_SIZE;
            array_offset = (offset + BLOCK_SIZE / 2) * matrix_dim + offset;
            for (i = BLOCK_SIZE / 2; i < BLOCK_SIZE; i++) {
                dia[i * BLOCK_SIZE + idx] = m[array_offset + idx];
                array_offset += matrix_dim;
            }

            array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
            for (i = 0; i < BLOCK_SIZE; i++) {
                peri_col[idx * BLOCK_SIZE + i] = m[array_offset + idx];
                array_offset += matrix_dim;
            }
        }

        // Computation Part 1: Update peri_row
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            idx = tx;
            for (i = 1; i < BLOCK_SIZE; i++) {
                float sum = 0.0f;
                for (j = 0; j < i; j++) {
                    sum += dia[i * BLOCK_SIZE + j] * peri_row[j * BLOCK_SIZE + idx];
                }
                peri_row[i * BLOCK_SIZE + idx] -= sum;
            }
        }

        // Computation Part 2: Update peri_col
        for (int tx = BLOCK_SIZE; tx < 2 * BLOCK_SIZE; tx++) {
            idx = tx - BLOCK_SIZE;
            for (i = 0; i < BLOCK_SIZE; i++) {
                float sum = 0.0f;
                for (j = 0; j < i; j++) {
                    sum += peri_col[idx * BLOCK_SIZE + j] * dia[j * BLOCK_SIZE + i];
                }
                peri_col[idx * BLOCK_SIZE + i] -= sum;
                peri_col[idx * BLOCK_SIZE + i] /= dia[i * BLOCK_SIZE + i];
            }
        }

        // Write back Part 1: peri_row
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            idx = tx;
            array_offset = (offset + 1) * matrix_dim + (offset + (bx + 1) * BLOCK_SIZE);
            for (i = 1; i < BLOCK_SIZE; i++) {
                m[array_offset + idx] = peri_row[i * BLOCK_SIZE + idx];
                array_offset += matrix_dim;
            }
        }

        // Write back Part 2: peri_col
        for (int tx = BLOCK_SIZE; tx < 2 * BLOCK_SIZE; tx++) {
            idx = tx - BLOCK_SIZE;
            array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
            for (i = 0; i < BLOCK_SIZE; i++) {
                m[array_offset + idx] = peri_col[i * BLOCK_SIZE + idx];
                array_offset += matrix_dim;
            }
        }
    }
}

void lud_internal(float *m, int matrix_dim, int offset) {
    int num_blocks = (matrix_dim - offset) / BLOCK_SIZE - 1;

    // Parallelize over the 2D grid of internal blocks (by, bx)
    #pragma omp parallel for collapse(2)
    for (int by = 0; by < num_blocks; by++) {
        for (int bx = 0; bx < num_blocks; bx++) {
            float peri_row[BLOCK_SIZE * BLOCK_SIZE];
            float peri_col[BLOCK_SIZE * BLOCK_SIZE];
            int tx, ty, i;
            float sum;

            int global_row_id = offset + (by + 1) * BLOCK_SIZE;
            int global_col_id = offset + (bx + 1) * BLOCK_SIZE;

            // Load
            for (ty = 0; ty < BLOCK_SIZE; ty++) {
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    peri_row[ty * BLOCK_SIZE + tx] = m[(offset + ty) * matrix_dim + global_col_id + tx];
                    peri_col[ty * BLOCK_SIZE + tx] = m[(global_row_id + ty) * matrix_dim + offset + tx];
                }
            }

            // Compute
            for (ty = 0; ty < BLOCK_SIZE; ty++) {
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    sum = 0.0f;
                    for (i = 0; i < BLOCK_SIZE; i++) {
                        sum += peri_col[ty * BLOCK_SIZE + i] * peri_row[i * BLOCK_SIZE + tx];
                    }
                    m[(global_row_id + ty) * matrix_dim + global_col_id + tx] -= sum;
                }
            }
        }
    }
}

void lud_omp(float *m, int matrix_dim) {
    int i;
    for (i = 0; i < matrix_dim - BLOCK_SIZE; i += BLOCK_SIZE) {
        lud_diagonal(m, matrix_dim, i);
        lud_perimeter(m, matrix_dim, i);
        lud_internal(m, matrix_dim, i);
    }
    // Final diagonal block
    lud_diagonal(m, matrix_dim, i);
}
